22	struct Buffer {
23	    EP_STATIC_ASSERT(LEGACY_NUM_MAX_NVL_PEERS == 8, "The number of maximum NVLink peers must be 8");
24	
25	private:
26	    // Low-latency mode buffer
27	    int low_latency_buffer_idx = 0;
28	    bool low_latency_mode = false;
29	
30	    // NVLink Buffer
31	    int64_t num_nvl_bytes;
32	    void* buffer_ptrs[LEGACY_NUM_MAX_NVL_PEERS] = {nullptr};
33	    void** buffer_ptrs_gpu = nullptr;
34	
35	    // NVSHMEM Buffer
36	    int64_t num_rdma_bytes;
37	    void* rdma_buffer_ptr = nullptr;
38	
39	    // Shrink mode buffer
40	    bool enable_shrink = false;
41	    int* mask_buffer_ptr = nullptr;
42	    int* sync_buffer_ptr = nullptr;
43	
44	    // Device info and communication
45	    int device_id;
46	    int num_device_sms;
47	    int rank, rdma_rank, nvl_rank;
48	    int num_ranks, num_rdma_ranks, num_nvl_ranks;
49	    shared_memory::MemHandle ipc_handles[LEGACY_NUM_MAX_NVL_PEERS];
50	
51	    // Stream for communication
52	    at::cuda::CUDAStream comm_stream;
53	
54	    // After IPC/NVSHMEM synchronization, this flag will be true
55	    bool available = false;
56	
57	    // Whether explicit `destroy()` is required.
58	    bool explicitly_destroy;
59	    // After `destroy()` be called, this flag will be true
60	    bool destroyed = false;
61	
62	    // Barrier signals
63	    int* barrier_signal_ptrs[LEGACY_NUM_MAX_NVL_PEERS] = {nullptr};
64	    int** barrier_signal_ptrs_gpu = nullptr;
65	
66	    // Workspace
67	    void* workspace = nullptr;
68	
69	    // Host-side MoE info
70	    volatile int* moe_recv_counter = nullptr;
71	    int* moe_recv_counter_mapped = nullptr;
72	
73	    // Host-side expert-level MoE info
74	    volatile int* moe_recv_expert_counter = nullptr;
75	    int* moe_recv_expert_counter_mapped = nullptr;
76	
77	    // Host-side RDMA-level MoE info
78	    volatile int* moe_recv_rdma_counter = nullptr;
79	    int* moe_recv_rdma_counter_mapped = nullptr;
80	
81	    shared_memory::SharedMemoryAllocator shared_memory_allocator;
82	
83	public:
84	    Buffer(int rank,
85	           int num_ranks,
86	           int64_t num_nvl_bytes,
87	           int64_t num_rdma_bytes,
88	           bool low_latency_mode,
89	           bool explicitly_destroy,
90	           bool enable_shrink,
91	           bool use_fabric) : rank(rank),
92	      num_ranks(num_ranks),
93	      num_nvl_bytes(num_nvl_bytes),
94	      num_rdma_bytes(num_rdma_bytes),
95	      enable_shrink(enable_shrink),
96	      low_latency_mode(low_latency_mode),
97	      explicitly_destroy(explicitly_destroy),
98	      comm_stream(at::cuda::getStreamFromPool(true)),
99	      shared_memory_allocator(use_fabric) {
100	        // Metadata memory
101	        int64_t barrier_signal_bytes = LEGACY_NUM_MAX_NVL_PEERS * sizeof(int);
102	        int64_t buffer_ptr_bytes = LEGACY_NUM_MAX_NVL_PEERS * sizeof(void*);
103	        int64_t barrier_signal_ptr_bytes = LEGACY_NUM_MAX_NVL_PEERS * sizeof(int*);
104	
105	        // Common checks
106	        EP_STATIC_ASSERT(LEGACY_NUM_BUFFER_ALIGNMENT_BYTES % sizeof(int4) == 0, "Invalid alignment");
107	        EP_HOST_ASSERT(num_nvl_bytes % LEGACY_NUM_BUFFER_ALIGNMENT_BYTES == 0 and
108	                       (num_nvl_bytes <= std::numeric_limits<int>::max() or num_rdma_bytes == 0));
109	        EP_HOST_ASSERT(num_rdma_bytes % LEGACY_NUM_BUFFER_ALIGNMENT_BYTES == 0 and
110	                       (low_latency_mode or num_rdma_bytes <= std::numeric_limits<int>::max()));
111	        EP_HOST_ASSERT(num_nvl_bytes / sizeof(int4) < std::numeric_limits<int>::max());
112	        EP_HOST_ASSERT(num_rdma_bytes / sizeof(int4) < std::numeric_limits<int>::max());
113	        EP_HOST_ASSERT(0 <= rank and rank < num_ranks and (num_ranks <= LEGACY_NUM_MAX_NVL_PEERS * LEGACY_NUM_MAX_RDMA_PEERS or low_latency_mode));
114	        EP_HOST_ASSERT(num_ranks < LEGACY_NUM_MAX_NVL_PEERS or num_ranks % LEGACY_NUM_MAX_NVL_PEERS == 0);
115	        if (num_rdma_bytes > 0)
116	            EP_HOST_ASSERT(num_ranks > LEGACY_NUM_MAX_NVL_PEERS or low_latency_mode);
117	
118	        // Get ranks
119	        CUDA_RUNTIME_CHECK(cudaGetDevice(&device_id));
120	        rdma_rank = rank / LEGACY_NUM_MAX_NVL_PEERS, nvl_rank = rank % LEGACY_NUM_MAX_NVL_PEERS;
121	        num_rdma_ranks = std::max(1, num_ranks / LEGACY_NUM_MAX_NVL_PEERS), num_nvl_ranks = std::min(num_ranks, LEGACY_NUM_MAX_NVL_PEERS);
122	
123	        // Get device info
124	        cudaDeviceProp device_prop = {};
125	        CUDA_RUNTIME_CHECK(cudaGetDeviceProperties(&device_prop, device_id));
126	        num_device_sms = device_prop.multiProcessorCount;
127	
128	        // Number of per-channel bytes cannot be large
129	        EP_HOST_ASSERT(ceil_div<int64_t>(num_nvl_bytes, num_device_sms / 2) < std::numeric_limits<int>::max());
130	        EP_HOST_ASSERT(ceil_div<int64_t>(num_rdma_bytes, num_device_sms / 2) < std::numeric_limits<int>::max());
131	
132	        if (num_nvl_bytes > 0) {
133	            // Local IPC: alloc local memory and set local IPC handles
134	            shared_memory_allocator.malloc(&buffer_ptrs[nvl_rank],
135	                                           num_nvl_bytes + barrier_signal_bytes + buffer_ptr_bytes + barrier_signal_ptr_bytes);
136	            shared_memory_allocator.get_mem_handle(&ipc_handles[nvl_rank], buffer_ptrs[nvl_rank]);
137	            buffer_ptrs_gpu = reinterpret_cast<void**>(static_cast<uint8_t*>(buffer_ptrs[nvl_rank]) + num_nvl_bytes + barrier_signal_bytes);
138	
139	            // Set barrier signals
140	            barrier_signal_ptrs[nvl_rank] = reinterpret_cast<int*>(static_cast<uint8_t*>(buffer_ptrs[nvl_rank]) + num_nvl_bytes);
141	            barrier_signal_ptrs_gpu =
142	                reinterpret_cast<int**>(static_cast<uint8_t*>(buffer_ptrs[nvl_rank]) + num_nvl_bytes + barrier_signal_bytes + buffer_ptr_bytes);
143	
144	            // No need to synchronize, will do a full device sync during `sync`
145	            CUDA_RUNTIME_CHECK(cudaMemsetAsync(barrier_signal_ptrs[nvl_rank], 0, barrier_signal_bytes, comm_stream));
146	        }
147	
148	        // Create 32 MiB workspace
149	        CUDA_RUNTIME_CHECK(cudaMalloc(&workspace, LEGACY_NUM_WORKSPACE_BYTES));
150	        CUDA_RUNTIME_CHECK(cudaMemsetAsync(workspace, 0, LEGACY_NUM_WORKSPACE_BYTES, comm_stream));
151	
152	        // MoE counter
153	        CUDA_RUNTIME_CHECK(cudaMallocHost(&moe_recv_counter, sizeof(int64_t), cudaHostAllocMapped));
154	        CUDA_RUNTIME_CHECK(cudaHostGetDevicePointer(&moe_recv_counter_mapped, const_cast<int*>(moe_recv_counter), 0));
155	        *moe_recv_counter = -1;
156	
157	        // MoE expert-level counter
158	        CUDA_RUNTIME_CHECK(cudaMallocHost(&moe_recv_expert_counter, sizeof(int) * LEGACY_NUM_MAX_LOCAL_EXPERTS, cudaHostAllocMapped));
159	        CUDA_RUNTIME_CHECK(cudaHostGetDevicePointer(&moe_recv_expert_counter_mapped, const_cast<int*>(moe_recv_expert_counter), 0));
160	        for (int i = 0; i < LEGACY_NUM_MAX_LOCAL_EXPERTS; ++i)
161	            moe_recv_expert_counter[i] = -1;
162	
163	        // MoE RDMA-level counter
164	        if (num_rdma_ranks > 0) {
165	            CUDA_RUNTIME_CHECK(cudaMallocHost(&moe_recv_rdma_counter, sizeof(int), cudaHostAllocMapped));
166	            CUDA_RUNTIME_CHECK(cudaHostGetDevicePointer(&moe_recv_rdma_counter_mapped, const_cast<int*>(moe_recv_rdma_counter), 0));
167	            *moe_recv_rdma_counter = -1;
168	        }
169	    }
170	
171	    ~Buffer() noexcept(false) {
172	        if (not explicitly_destroy) {
173	            destroy();
174	        } else if (not destroyed) {
175	            printf("WARNING: destroy() was not called before DeepEP buffer destruction, which can leak resources.\n");
176	            fflush(stdout);
177	        }
178	    }
