215	    torch::Tensor get_local_buffer_tensor(const pybind11::object& dtype, int64_t offset, bool use_rdma_buffer) const {
216	        torch::ScalarType casted_dtype = torch::python::detail::py_object_to_dtype(dtype);
217	        auto element_bytes = static_cast<int64_t>(elementSize(casted_dtype));
218	        auto base_ptr = static_cast<uint8_t*>(use_rdma_buffer ? rdma_buffer_ptr : buffer_ptrs[nvl_rank]) + offset;
219	        auto num_bytes = use_rdma_buffer ? num_rdma_bytes : num_nvl_bytes;
220	        return torch::from_blob(base_ptr, num_bytes / element_bytes, torch::TensorOptions().dtype(casted_dtype).device(at::kCUDA));
221	    }
