227	    void sync(const std::vector<int>& device_ids,
228	              const std::vector<std::optional<pybind11::bytearray>>& all_gathered_handles,
229	              const std::optional<pybind11::bytearray>& root_unique_id_opt) {
230	        EP_HOST_ASSERT(not is_available());
231	
232	        // Sync IPC handles
233	        if (num_nvl_bytes > 0) {
234	            EP_HOST_ASSERT(num_ranks == device_ids.size());
235	            EP_HOST_ASSERT(device_ids.size() == all_gathered_handles.size());
236	            for (int i = 0, offset = rdma_rank * num_nvl_ranks; i < num_nvl_ranks; ++i) {
237	                EP_HOST_ASSERT(all_gathered_handles[offset + i].has_value());
238	                auto handle_str = std::string(all_gathered_handles[offset + i].value());
239	                EP_HOST_ASSERT(handle_str.size() == sizeof(shared_memory::MemHandle));
240	                if (offset + i != rank) {
241	                    std::memcpy(&ipc_handles[i], handle_str.c_str(), sizeof(shared_memory::MemHandle));
242	                    shared_memory_allocator.open_mem_handle(&buffer_ptrs[i], &ipc_handles[i]);
243	                    barrier_signal_ptrs[i] = reinterpret_cast<int*>(static_cast<uint8_t*>(buffer_ptrs[i]) + num_nvl_bytes);
244	                } else {
245	                    EP_HOST_ASSERT(std::memcmp(&ipc_handles[i], handle_str.c_str(), sizeof(shared_memory::MemHandle)) == 0);
246	                }
247	            }
248	
249	            // Copy all buffer and barrier signal pointers to GPU
250	            CUDA_RUNTIME_CHECK(cudaMemcpy(buffer_ptrs_gpu, buffer_ptrs, sizeof(void*) * LEGACY_NUM_MAX_NVL_PEERS, cudaMemcpyHostToDevice));
251	            CUDA_RUNTIME_CHECK(cudaMemcpy(barrier_signal_ptrs_gpu, barrier_signal_ptrs, sizeof(int*) * LEGACY_NUM_MAX_NVL_PEERS, cudaMemcpyHostToDevice));
252	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
253	        }
254	
255	        // Sync NVSHMEM handles and allocate memory
256	        if (num_rdma_bytes > 0) {
257	            // Initialize NVSHMEM
258	            EP_HOST_ASSERT(root_unique_id_opt.has_value());
259	            std::vector<uint8_t> root_unique_id(root_unique_id_opt->size());
260	            auto root_unique_id_str = root_unique_id_opt->cast<std::string>();
261	            std::memcpy(root_unique_id.data(), root_unique_id_str.c_str(), root_unique_id_opt->size());
262	            auto nvshmem_rank = low_latency_mode ? rank : rdma_rank;
263	            auto num_nvshmem_ranks = low_latency_mode ? num_ranks : num_rdma_ranks;
264	            EP_HOST_ASSERT(nvshmem_rank == nvshmem::init(root_unique_id, nvshmem_rank, num_nvshmem_ranks,
265	                                                         low_latency_mode ? LEGACY_NUM_MAX_NVL_PEERS : 0));
266	
267	            // Allocate
268	            rdma_buffer_ptr = nvshmem::alloc(num_rdma_bytes, LEGACY_NUM_BUFFER_ALIGNMENT_BYTES);
269	
270	            // Clean buffer (mainly for low-latency mode)
271	            CUDA_RUNTIME_CHECK(cudaMemset(rdma_buffer_ptr, 0, num_rdma_bytes));
272	
273	            // Allocate and clean shrink buffer
274	            if (enable_shrink) {
275	                int num_mask_buffer_bytes = num_ranks * sizeof(int);
276	                int num_sync_buffer_bytes = num_ranks * sizeof(int);
277	                mask_buffer_ptr = static_cast<int*>(nvshmem::alloc(num_mask_buffer_bytes, LEGACY_NUM_BUFFER_ALIGNMENT_BYTES));
278	                sync_buffer_ptr = static_cast<int*>(nvshmem::alloc(num_sync_buffer_bytes, LEGACY_NUM_BUFFER_ALIGNMENT_BYTES));
279	                CUDA_RUNTIME_CHECK(cudaMemset(mask_buffer_ptr, 0, num_mask_buffer_bytes));
280	                CUDA_RUNTIME_CHECK(cudaMemset(sync_buffer_ptr, 0, num_sync_buffer_bytes));
281	            }
282	
283	            // Barrier
284	            nvshmem::barrier(true);
285	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
286	        }
287	
288	        // Ready to use
289	        available = true;
290	    }
