292	    void destroy() {
293	        EP_HOST_ASSERT(not destroyed);
294	
295	        // Synchronize
296	        CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
297	
298	        if (num_nvl_bytes > 0) {
299	            // Barrier
300	            intranode::barrier(barrier_signal_ptrs_gpu, nvl_rank, num_nvl_ranks, comm_stream);
301	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
302	
303	            // Close remote IPC
304	            if (is_available()) {
305	                for (int i = 0; i < num_nvl_ranks; ++i)
306	                    if (i != nvl_rank)
307	                        shared_memory_allocator.close_mem_handle(buffer_ptrs[i]);
308	            }
309	
310	            // Free local buffer and error flag
311	            shared_memory_allocator.free(buffer_ptrs[nvl_rank]);
312	        }
313	
314	        // Free NVSHMEM
315	        if (is_available() and num_rdma_bytes > 0) {
316	            CUDA_RUNTIME_CHECK(cudaDeviceSynchronize());
317	            nvshmem::barrier(true);
318	            nvshmem::free(rdma_buffer_ptr);
319	            if (enable_shrink) {
320	                nvshmem::free(mask_buffer_ptr);
321	                nvshmem::free(sync_buffer_ptr);
322	            }
323	            nvshmem::finalize();
324	        }
325	
326	        // Free workspace and MoE counter
327	        CUDA_RUNTIME_CHECK(cudaFree(workspace));
328	        CUDA_RUNTIME_CHECK(cudaFreeHost(const_cast<int*>(moe_recv_counter)));
329	
330	        // Free chunked mode staffs
331	        CUDA_RUNTIME_CHECK(cudaFreeHost(const_cast<int*>(moe_recv_expert_counter)));
332	
333	        destroyed = true;
334	        available = false;
335	    }
