337	    std::tuple<torch::Tensor, std::optional<torch::Tensor>, torch::Tensor, torch::Tensor, std::optional<EventHandle>> get_dispatch_layout(
338	        const torch::Tensor& topk_idx,
339	        int num_experts,
340	        const std::optional<EventHandle>& previous_event,
341	        bool async,
342	        bool allocate_on_comm_stream) {
343	        EP_HOST_ASSERT(topk_idx.dim() == 2);
344	        EP_HOST_ASSERT(topk_idx.is_contiguous());
345	        EP_HOST_ASSERT(num_experts > 0);
346	
347	        // Allocate all tensors on comm stream if set
348	        // NOTES: do not allocate tensors upfront!
349	        auto compute_stream = at::cuda::getCurrentCUDAStream();
350	        if (allocate_on_comm_stream) {
351	            EP_HOST_ASSERT(previous_event.has_value() and async);
352	            at::cuda::setCurrentCUDAStream(comm_stream);
353	        }
354	
355	        // Wait previous tasks to be finished
356	        if (previous_event.has_value()) {
357	            stream_wait(comm_stream, previous_event.value());
358	        } else {
359	            stream_wait(comm_stream, compute_stream);
360	        }
361	
362	        auto num_tokens = static_cast<int>(topk_idx.size(0)), num_topk = static_cast<int>(topk_idx.size(1));
363	        auto num_tokens_per_rank = torch::empty({num_ranks}, dtype(torch::kInt32).device(torch::kCUDA));
364	        auto num_tokens_per_rdma_rank = std::optional<torch::Tensor>();
365	        auto num_tokens_per_expert = torch::empty({num_experts}, dtype(torch::kInt32).device(torch::kCUDA));
366	        auto is_token_in_rank = torch::empty({num_tokens, num_ranks}, dtype(torch::kBool).device(torch::kCUDA));
367	        if (is_internode_available())
368	            num_tokens_per_rdma_rank = torch::empty({num_rdma_ranks}, dtype(torch::kInt32).device(torch::kCUDA));
369	
370	        layout::get_dispatch_layout(topk_idx.data_ptr<topk_idx_t>(),
371	                                    num_tokens_per_rank.data_ptr<int>(),
372	                                    num_tokens_per_rdma_rank.has_value() ? num_tokens_per_rdma_rank.value().data_ptr<int>() : nullptr,
373	                                    num_tokens_per_expert.data_ptr<int>(),
374	                                    is_token_in_rank.data_ptr<bool>(),
375	                                    num_tokens,
376	                                    num_topk,
377	                                    num_ranks,
378	                                    num_experts,
379	                                    comm_stream);
380	
381	        // Wait streams
382	        std::optional<EventHandle> event;
383	        if (async) {
384	            event = EventHandle(comm_stream);
385	            for (auto& t : {topk_idx, num_tokens_per_rank, num_tokens_per_expert, is_token_in_rank}) {
386	                t.record_stream(comm_stream);
387	                if (allocate_on_comm_stream)
388	                    t.record_stream(compute_stream);
389	            }
390	            for (auto& to : {num_tokens_per_rdma_rank}) {
391	                to.has_value() ? to->record_stream(comm_stream) : void();
392	                if (allocate_on_comm_stream)
393	                    to.has_value() ? to->record_stream(compute_stream) : void();
394	            }
395	        } else {
396	            stream_wait(compute_stream, comm_stream);
397	        }
398	
399	        // Switch back compute stream
400	        if (allocate_on_comm_stream)
401	            at::cuda::setCurrentCUDAStream(compute_stream);
402	
403	        return {num_tokens_per_rank, num_tokens_per_rdma_rank, num_tokens_per_expert, is_token_in_rank, event};
404	    }
