406	    std::tuple<torch::Tensor,
407	               std::optional<torch::Tensor>,
408	               std::optional<torch::Tensor>,
409	               std::optional<torch::Tensor>,
410	               std::vector<int>,
411	               torch::Tensor,
412	               torch::Tensor,
413	               torch::Tensor,
414	               torch::Tensor,
415	               torch::Tensor,
416	               std::optional<EventHandle>>
417	    intranode_dispatch(const torch::Tensor& x,
418	                       const std::optional<torch::Tensor>& x_scales,
419	                       const std::optional<torch::Tensor>& topk_idx,
420	                       const std::optional<torch::Tensor>& topk_weights,
421	                       const std::optional<torch::Tensor>& num_tokens_per_rank,
422	                       const torch::Tensor& is_token_in_rank,
423	                       const std::optional<torch::Tensor>& num_tokens_per_expert,
424	                       int cached_num_recv_tokens,
425	                       const std::optional<torch::Tensor>& cached_rank_prefix_matrix,
426	                       const std::optional<torch::Tensor>& cached_channel_prefix_matrix,
427	                       int expert_alignment,
428	                       int num_worst_tokens,
429	                       const Config& config,
430	                       std::optional<EventHandle>& previous_event,
431	                       bool async,
432	                       bool allocate_on_comm_stream) {
433	        bool cached_mode = cached_rank_prefix_matrix.has_value();
434	
435	        // One channel use two blocks, even-numbered blocks for sending, odd-numbered blocks for receiving.
436	        EP_HOST_ASSERT(config.num_sms % 2 == 0);
437	        int num_channels = config.num_sms / 2;
438	        if (cached_mode) {
439	            EP_HOST_ASSERT(cached_rank_prefix_matrix.has_value());
440	            EP_HOST_ASSERT(cached_channel_prefix_matrix.has_value());
441	        } else {
442	            EP_HOST_ASSERT(num_tokens_per_rank.has_value());
443	            EP_HOST_ASSERT(num_tokens_per_expert.has_value());
444	        }
445	
446	        // Type checks
447	        EP_HOST_ASSERT(is_token_in_rank.scalar_type() == torch::kBool);
448	        if (cached_mode) {
449	            EP_HOST_ASSERT(cached_rank_prefix_matrix->scalar_type() == torch::kInt32);
450	            EP_HOST_ASSERT(cached_channel_prefix_matrix->scalar_type() == torch::kInt32);
451	        } else {
452	            EP_HOST_ASSERT(num_tokens_per_expert->scalar_type() == torch::kInt32);
453	            EP_HOST_ASSERT(num_tokens_per_rank->scalar_type() == torch::kInt32);
454	        }
455	
456	        // Shape and contiguous checks
457	        EP_HOST_ASSERT(x.dim() == 2 and x.is_contiguous());
458	        EP_HOST_ASSERT((x.size(1) * x.element_size()) % sizeof(int4) == 0);
459	        EP_HOST_ASSERT(is_token_in_rank.dim() == 2 and is_token_in_rank.is_contiguous());
460	        EP_HOST_ASSERT(is_token_in_rank.size(0) == x.size(0) and is_token_in_rank.size(1) == num_ranks);
461	        if (cached_mode) {
462	            EP_HOST_ASSERT(cached_rank_prefix_matrix->dim() == 2 and cached_rank_prefix_matrix->is_contiguous());
463	            EP_HOST_ASSERT(cached_rank_prefix_matrix->size(0) == num_ranks and cached_rank_prefix_matrix->size(1) == num_ranks);
464	            EP_HOST_ASSERT(cached_channel_prefix_matrix->dim() == 2 and cached_channel_prefix_matrix->is_contiguous());
465	            EP_HOST_ASSERT(cached_channel_prefix_matrix->size(0) == num_ranks and cached_channel_prefix_matrix->size(1) == num_channels);
466	        } else {
467	            EP_HOST_ASSERT(num_tokens_per_expert->dim() == 1 and num_tokens_per_expert->is_contiguous());
468	            EP_HOST_ASSERT(num_tokens_per_expert->size(0) % num_ranks == 0);
469	            EP_HOST_ASSERT(num_tokens_per_expert->size(0) / num_ranks <= LEGACY_NUM_MAX_LOCAL_EXPERTS);
470	            EP_HOST_ASSERT(num_tokens_per_rank->dim() == 1 and num_tokens_per_rank->is_contiguous());
471	            EP_HOST_ASSERT(num_tokens_per_rank->size(0) == num_ranks);
472	        }
473	
474	        auto num_tokens = static_cast<int>(x.size(0)), hidden = static_cast<int>(x.size(1));
475	        auto num_experts = cached_mode ? 0 : static_cast<int>(num_tokens_per_expert->size(0)), num_local_experts = num_experts / num_ranks;
476	
477	        // Top-k checks
478	        int num_topk = 0;
479	        topk_idx_t* topk_idx_ptr = nullptr;
480	        float* topk_weights_ptr = nullptr;
481	        EP_HOST_ASSERT(topk_idx.has_value() == topk_weights.has_value());
482	        if (topk_idx.has_value()) {
483	            num_topk = static_cast<int>(topk_idx->size(1));
484	            EP_HOST_ASSERT(num_experts > 0);
485	            EP_HOST_ASSERT(topk_idx->dim() == 2 and topk_idx->is_contiguous());
486	            EP_HOST_ASSERT(topk_weights->dim() == 2 and topk_weights->is_contiguous());
487	            EP_HOST_ASSERT(num_tokens == topk_idx->size(0) and num_tokens == topk_weights->size(0));
488	            EP_HOST_ASSERT(num_topk == topk_weights->size(1));
489	            EP_HOST_ASSERT(topk_weights->scalar_type() == torch::kFloat32);
490	            topk_idx_ptr = topk_idx->data_ptr<topk_idx_t>();
491	            topk_weights_ptr = topk_weights->data_ptr<float>();
492	        }
493	
494	        // FP8 scales checks
495	        float* x_scales_ptr = nullptr;
496	        int num_scales = 0, scale_token_stride = 0, scale_hidden_stride = 0;
497	        if (x_scales.has_value()) {
498	            EP_HOST_ASSERT(x.element_size() == 1);
499	            EP_HOST_ASSERT(x_scales->scalar_type() == torch::kFloat32 or x_scales->scalar_type() == torch::kInt);
500	            EP_HOST_ASSERT(x_scales->dim() == 2);
501	            EP_HOST_ASSERT(x_scales->size(0) == num_tokens);
502	            num_scales = x_scales->dim() == 1 ? 1 : static_cast<int>(x_scales->size(1));
503	            x_scales_ptr = static_cast<float*>(x_scales->data_ptr());
504	            scale_token_stride = static_cast<int>(x_scales->stride(0));
505	            scale_hidden_stride = static_cast<int>(x_scales->stride(1));
506	        }
507	
508	        // Allocate all tensors on comm stream if set
509	        // NOTES: do not allocate tensors upfront!
510	        auto compute_stream = at::cuda::getCurrentCUDAStream();
511	        if (allocate_on_comm_stream) {
512	            EP_HOST_ASSERT(previous_event.has_value() and async);
513	            at::cuda::setCurrentCUDAStream(comm_stream);
514	        }
515	
516	        // Wait previous tasks to be finished
517	        if (previous_event.has_value()) {
518	            stream_wait(comm_stream, previous_event.value());
519	        } else {
520	            stream_wait(comm_stream, compute_stream);
521	        }
522	
523	        // Create handles (only return for non-cached mode)
524	        int num_recv_tokens = -1;
525	        auto rank_prefix_matrix = torch::Tensor();
526	        auto channel_prefix_matrix = torch::Tensor();
527	        std::vector<int> num_recv_tokens_per_expert_list;
528	
529	        // Barrier or send sizes
530	        // To clean: channel start/end offset, head and tail
531	        int num_memset_int = num_channels * num_ranks * 4;
532	        if (cached_mode) {
533	            num_recv_tokens = cached_num_recv_tokens;
534	            rank_prefix_matrix = cached_rank_prefix_matrix.value();
535	            channel_prefix_matrix = cached_channel_prefix_matrix.value();
536	
537	            // Copy rank prefix matrix and clean flags
538	            intranode::cached_notify_dispatch(
539	                rank_prefix_matrix.data_ptr<int>(), num_memset_int, buffer_ptrs_gpu, barrier_signal_ptrs_gpu, rank, num_ranks, comm_stream);
540	        } else {
541	            rank_prefix_matrix = torch::empty({num_ranks, num_ranks}, dtype(torch::kInt32).device(torch::kCUDA));
542	            channel_prefix_matrix = torch::empty({num_ranks, num_channels}, dtype(torch::kInt32).device(torch::kCUDA));
543	
544	            // Send sizes
545	            // Meta information:
546	            //  - Size prefix by ranks, shaped as `[num_ranks, num_ranks]`
547	            //  - Size prefix by experts (not used later), shaped as `[num_ranks, num_local_experts]`
548	            // NOTES: no more token dropping in this version
549	            *moe_recv_counter = -1;
550	            for (int i = 0; i < num_local_experts; ++i)
551	                moe_recv_expert_counter[i] = -1;
552	            EP_HOST_ASSERT(num_ranks * (num_ranks + num_local_experts) * sizeof(int) <= num_nvl_bytes);
553	            intranode::notify_dispatch(num_tokens_per_rank->data_ptr<int>(),
554	                                       moe_recv_counter_mapped,
555	                                       num_ranks,
556	                                       num_tokens_per_expert->data_ptr<int>(),
557	                                       moe_recv_expert_counter_mapped,
558	                                       num_experts,
559	                                       num_tokens,
560	                                       is_token_in_rank.data_ptr<bool>(),
561	                                       channel_prefix_matrix.data_ptr<int>(),
562	                                       rank_prefix_matrix.data_ptr<int>(),
563	                                       num_memset_int,
564	                                       expert_alignment,
565	                                       buffer_ptrs_gpu,
566	                                       barrier_signal_ptrs_gpu,
567	                                       rank,
568	                                       comm_stream,
569	                                       num_channels);
570	
571	            if (num_worst_tokens > 0) {
572	                // No CPU sync, just allocate the worst case
573	                num_recv_tokens = num_worst_tokens;
574	
575	                // Must be forward with top-k stuffs
576	                EP_HOST_ASSERT(topk_idx.has_value());
577	                EP_HOST_ASSERT(topk_weights.has_value());
578	            } else {
579	                // Synchronize total received tokens and tokens per expert
580	                auto start_time = std::chrono::high_resolution_clock::now();
581	                while (true) {
582	                    // Read total count
583	                    num_recv_tokens = static_cast<int>(*moe_recv_counter);
584	
585	                    // Read per-expert count
586	                    bool ready = (num_recv_tokens >= 0);
587	                    for (int i = 0; i < num_local_experts and ready; ++i)
588	                        ready &= moe_recv_expert_counter[i] >= 0;
589	
590	                    if (ready)
591	                        break;
592	
593	                    // Timeout check
594	                    if (std::chrono::duration_cast<std::chrono::seconds>(std::chrono::high_resolution_clock::now() - start_time).count() >
595	                        LEGACY_NUM_CPU_TIMEOUT_SECS)
596	                        throw std::runtime_error("DeepEP error: CPU recv timeout");
597	                }
598	                num_recv_tokens_per_expert_list = std::vector<int>(moe_recv_expert_counter, moe_recv_expert_counter + num_local_experts);
599	            }
600	        }
601	
602	        // Allocate new tensors
603	        auto recv_x = torch::empty({num_recv_tokens, hidden}, x.options());
604	        auto recv_src_idx = torch::empty({num_recv_tokens}, dtype(torch::kInt32).device(torch::kCUDA));
605	        auto recv_topk_idx = std::optional<torch::Tensor>(), recv_topk_weights = std::optional<torch::Tensor>(),
606	             recv_x_scales = std::optional<torch::Tensor>();
607	        auto recv_channel_prefix_matrix = torch::empty({num_ranks, num_channels}, dtype(torch::kInt32).device(torch::kCUDA));
608	        auto send_head = torch::empty({num_tokens, num_ranks}, dtype(torch::kInt32).device(torch::kCUDA));
609	
610	        // Assign pointers
611	        topk_idx_t* recv_topk_idx_ptr = nullptr;
612	        float* recv_topk_weights_ptr = nullptr;
613	        float* recv_x_scales_ptr = nullptr;
614	        if (topk_idx.has_value()) {
615	            recv_topk_idx = torch::empty({num_recv_tokens, num_topk}, topk_idx->options());
616	            recv_topk_weights = torch::empty({num_recv_tokens, num_topk}, topk_weights->options());
617	            recv_topk_idx_ptr = recv_topk_idx->data_ptr<topk_idx_t>();
618	            recv_topk_weights_ptr = recv_topk_weights->data_ptr<float>();
619	        }
620	        if (x_scales.has_value()) {
621	            recv_x_scales = x_scales->dim() == 1 ? torch::empty({num_recv_tokens}, x_scales->options())
622	                                                 : torch::empty({num_recv_tokens, num_scales}, x_scales->options());
623	            recv_x_scales_ptr = static_cast<float*>(recv_x_scales->data_ptr());
624	        }
625	
626	        // Dispatch
627	        EP_HOST_ASSERT(
628	            num_ranks * num_ranks * sizeof(int) +                                                                     // Size prefix matrix
629	                num_channels * num_ranks * sizeof(int) +                                                              // Channel start offset
630	                num_channels * num_ranks * sizeof(int) +                                                              // Channel end offset
631	                num_channels * num_ranks * sizeof(int) * 2 +                                                          // Queue head and tail
632	                num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * hidden * recv_x.element_size() +  // Data buffer
633	                num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * sizeof(int) +                     // Source index buffer
634	                num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * num_topk * sizeof(topk_idx_t) +   // Top-k index buffer
635	                num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * num_topk * sizeof(float) +        // Top-k weight buffer
636	                num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * sizeof(float) * num_scales        // FP8 scale buffer
637	            <= num_nvl_bytes);
638	        intranode::dispatch(recv_x.data_ptr(),
639	                            recv_x_scales_ptr,
640	                            recv_src_idx.data_ptr<int>(),
641	                            recv_topk_idx_ptr,
642	                            recv_topk_weights_ptr,
643	                            recv_channel_prefix_matrix.data_ptr<int>(),
644	                            send_head.data_ptr<int>(),
645	                            x.data_ptr(),
646	                            x_scales_ptr,
647	                            topk_idx_ptr,
648	                            topk_weights_ptr,
649	                            is_token_in_rank.data_ptr<bool>(),
650	                            channel_prefix_matrix.data_ptr<int>(),
651	                            num_tokens,
652	                            num_worst_tokens,
653	                            static_cast<int>(hidden * recv_x.element_size() / sizeof(int4)),
654	                            num_topk,
655	                            num_experts,
656	                            num_scales,
657	                            scale_token_stride,
658	                            scale_hidden_stride,
659	                            buffer_ptrs_gpu,
660	                            rank,
661	                            num_ranks,
662	                            comm_stream,
663	                            config.num_sms,
664	                            config.num_max_nvl_chunked_send_tokens,
665	                            config.num_max_nvl_chunked_recv_tokens);
666	
667	        // Wait streams
668	        std::optional<EventHandle> event;
669	        if (async) {
670	            event = EventHandle(comm_stream);
671	            for (auto& t : {x,
672	                            is_token_in_rank,
673	                            rank_prefix_matrix,
674	                            channel_prefix_matrix,
675	                            recv_x,
676	                            recv_src_idx,
677	                            recv_channel_prefix_matrix,
678	                            send_head}) {
679	                t.record_stream(comm_stream);
680	                if (allocate_on_comm_stream)
681	                    t.record_stream(compute_stream);
682	            }
683	            for (auto& to : {x_scales,
684	                             topk_idx,
685	                             topk_weights,
686	                             num_tokens_per_rank,
687	                             num_tokens_per_expert,
688	                             cached_channel_prefix_matrix,
689	                             cached_rank_prefix_matrix,
690	                             recv_topk_idx,
691	                             recv_topk_weights,
692	                             recv_x_scales}) {
693	                to.has_value() ? to->record_stream(comm_stream) : void();
694	                if (allocate_on_comm_stream)
695	                    to.has_value() ? to->record_stream(compute_stream) : void();
696	            }
697	        } else {
698	            stream_wait(compute_stream, comm_stream);
699	        }
700	
701	        // Switch back compute stream
702	        if (allocate_on_comm_stream)
703	            at::cuda::setCurrentCUDAStream(compute_stream);
704	
705	        // Return values
706	        return {recv_x,
707	                recv_x_scales,
708	                recv_topk_idx,
709	                recv_topk_weights,
710	                num_recv_tokens_per_expert_list,
711	                rank_prefix_matrix,
712	                channel_prefix_matrix,
713	                recv_channel_prefix_matrix,
714	                recv_src_idx,
715	                send_head,
716	                event};
717	    }
