719	    std::tuple<torch::Tensor, std::optional<torch::Tensor>, std::optional<EventHandle>> intranode_combine(
720	        const torch::Tensor& x,
721	        const std::optional<torch::Tensor>& topk_weights,
722	        const std::optional<torch::Tensor>& bias_0,
723	        const std::optional<torch::Tensor>& bias_1,
724	        const torch::Tensor& src_idx,
725	        const torch::Tensor& rank_prefix_matrix,
726	        const torch::Tensor& channel_prefix_matrix,
727	        const torch::Tensor& send_head,
728	        const Config& config,
729	        const std::optional<EventHandle>& previous_event,
730	        bool async,
731	        bool allocate_on_comm_stream) {
732	        EP_HOST_ASSERT(x.dim() == 2 and x.is_contiguous());
733	        EP_HOST_ASSERT(src_idx.dim() == 1 and src_idx.is_contiguous() and src_idx.scalar_type() == torch::kInt32);
734	        EP_HOST_ASSERT(send_head.dim() == 2 and send_head.is_contiguous() and send_head.scalar_type() == torch::kInt32);
735	        EP_HOST_ASSERT(rank_prefix_matrix.dim() == 2 and rank_prefix_matrix.is_contiguous() and
736	                       rank_prefix_matrix.scalar_type() == torch::kInt32);
737	        EP_HOST_ASSERT(channel_prefix_matrix.dim() == 2 and channel_prefix_matrix.is_contiguous() and
738	                       channel_prefix_matrix.scalar_type() == torch::kInt32);
739	
740	        // One channel use two blocks, even-numbered blocks for sending, odd-numbered blocks for receiving.
741	        EP_HOST_ASSERT(config.num_sms % 2 == 0);
742	        int num_channels = config.num_sms / 2;
743	
744	        auto num_tokens = static_cast<int>(x.size(0)), hidden = static_cast<int>(x.size(1));
745	        auto num_recv_tokens = static_cast<int>(send_head.size(0));
746	        EP_HOST_ASSERT(src_idx.size(0) == num_tokens);
747	        EP_HOST_ASSERT(send_head.size(1) == num_ranks);
748	        EP_HOST_ASSERT(rank_prefix_matrix.size(0) == num_ranks and rank_prefix_matrix.size(1) == num_ranks);
749	        EP_HOST_ASSERT(channel_prefix_matrix.size(0) == num_ranks and channel_prefix_matrix.size(1) == num_channels);
750	        EP_HOST_ASSERT((hidden * x.element_size()) % sizeof(int4) == 0);
751	
752	        // Allocate all tensors on comm stream if set
753	        // NOTES: do not allocate tensors upfront!
754	        auto compute_stream = at::cuda::getCurrentCUDAStream();
755	        if (allocate_on_comm_stream) {
756	            EP_HOST_ASSERT(previous_event.has_value() and async);
757	            at::cuda::setCurrentCUDAStream(comm_stream);
758	        }
759	
760	        // Wait previous tasks to be finished
761	        if (previous_event.has_value()) {
762	            stream_wait(comm_stream, previous_event.value());
763	        } else {
764	            stream_wait(comm_stream, compute_stream);
765	        }
766	
767	        int num_topk = 0;
768	        auto recv_topk_weights = std::optional<torch::Tensor>();
769	        float* topk_weights_ptr = nullptr;
770	        float* recv_topk_weights_ptr = nullptr;
771	        if (topk_weights.has_value()) {
772	            EP_HOST_ASSERT(topk_weights->dim() == 2 and topk_weights->is_contiguous());
773	            EP_HOST_ASSERT(topk_weights->size(0) == num_tokens);
774	            EP_HOST_ASSERT(topk_weights->scalar_type() == torch::kFloat32);
775	            num_topk = static_cast<int>(topk_weights->size(1));
776	            topk_weights_ptr = topk_weights->data_ptr<float>();
777	            recv_topk_weights = torch::empty({num_recv_tokens, num_topk}, topk_weights->options());
778	            recv_topk_weights_ptr = recv_topk_weights->data_ptr<float>();
779	        }
780	
781	        // Launch barrier and reset queue head and tail
782	        EP_HOST_ASSERT(num_channels * num_ranks * sizeof(int) * 2 <= num_nvl_bytes);
783	        intranode::cached_notify_combine(buffer_ptrs_gpu,
784	                                         send_head.data_ptr<int>(),
785	                                         num_channels,
786	                                         num_recv_tokens,
787	                                         num_channels * num_ranks * 2,
788	                                         barrier_signal_ptrs_gpu,
789	                                         rank,
790	                                         num_ranks,
791	                                         comm_stream);
792	
793	        // Assign bias pointers
794	        auto bias_opts = std::vector<std::optional<torch::Tensor>>({bias_0, bias_1});
795	        void* bias_ptrs[2] = {nullptr, nullptr};
796	        for (int i = 0; i < 2; ++i)
797	            if (bias_opts[i].has_value()) {
798	                auto bias = bias_opts[i].value();
799	                EP_HOST_ASSERT(bias.dim() == 2 and bias.is_contiguous());
800	                EP_HOST_ASSERT(bias.scalar_type() == x.scalar_type());
801	                EP_HOST_ASSERT(bias.size(0) == num_recv_tokens and bias.size(1) == hidden);
802	                bias_ptrs[i] = bias.data_ptr();
803	            }
804	
805	        // Combine data
806	        auto recv_x = torch::empty({num_recv_tokens, hidden}, x.options());
807	        EP_HOST_ASSERT(num_channels * num_ranks * sizeof(int) * 2 +  // Queue head and tail
808	                           num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * hidden * x.element_size() +  // Data buffer
809	                           num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * sizeof(int) +             // Source index buffer
810	                           num_channels * num_ranks * config.num_max_nvl_chunked_recv_tokens * num_topk * sizeof(float)  // Top-k weight buffer
811	                       <= num_nvl_bytes);
812	        intranode::combine(at::cuda::ScalarTypeToCudaDataType(x.scalar_type()),
813	                           recv_x.data_ptr(),
814	                           recv_topk_weights_ptr,
815	                           x.data_ptr(),
816	                           topk_weights_ptr,
817	                           bias_ptrs[0],
818	                           bias_ptrs[1],
819	                           src_idx.data_ptr<int>(),
820	                           rank_prefix_matrix.data_ptr<int>(),
821	                           channel_prefix_matrix.data_ptr<int>(),
822	                           send_head.data_ptr<int>(),
823	                           num_tokens,
824	                           num_recv_tokens,
825	                           hidden,
826	                           num_topk,
827	                           buffer_ptrs_gpu,
828	                           rank,
829	                           num_ranks,
830	                           comm_stream,
831	                           config.num_sms,
832	                           config.num_max_nvl_chunked_send_tokens,
833	                           config.num_max_nvl_chunked_recv_tokens);
834	
835	        // Wait streams
836	        std::optional<EventHandle> event;
837	        if (async) {
838	            event = EventHandle(comm_stream);
839	            for (auto& t : {x, src_idx, send_head, rank_prefix_matrix, channel_prefix_matrix, recv_x}) {
840	                t.record_stream(comm_stream);
841	                if (allocate_on_comm_stream)
842	                    t.record_stream(compute_stream);
843	            }
844	            for (auto& to : {topk_weights, recv_topk_weights, bias_0, bias_1}) {
845	                to.has_value() ? to->record_stream(comm_stream) : void();
846	                if (allocate_on_comm_stream)
847	                    to.has_value() ? to->record_stream(compute_stream) : void();
848	            }
849	        } else {
850	            stream_wait(compute_stream, comm_stream);
851	        }
852	
853	        // Switch back compute stream
854	        if (allocate_on_comm_stream)
855	            at::cuda::setCurrentCUDAStream(compute_stream);
856	
857	        return {recv_x, recv_topk_weights, event};
858	    }
