860	    std::tuple<torch::Tensor,
861	               std::optional<torch::Tensor>,
862	               std::optional<torch::Tensor>,
863	               std::optional<torch::Tensor>,
864	               std::vector<int>,
865	               torch::Tensor,
866	               torch::Tensor,
867	               std::optional<torch::Tensor>,
868	               torch::Tensor,
869	               std::optional<torch::Tensor>,
870	               torch::Tensor,
871	               std::optional<torch::Tensor>,
872	               std::optional<torch::Tensor>,
873	               std::optional<torch::Tensor>,
874	               std::optional<EventHandle>>
875	    internode_dispatch(const torch::Tensor& x,
876	                       const std::optional<torch::Tensor>& x_scales,
877	                       const std::optional<torch::Tensor>& topk_idx,
878	                       const std::optional<torch::Tensor>& topk_weights,
879	                       const std::optional<torch::Tensor>& num_tokens_per_rank,
880	                       const std::optional<torch::Tensor>& num_tokens_per_rdma_rank,
881	                       const torch::Tensor& is_token_in_rank,
882	                       const std::optional<torch::Tensor>& num_tokens_per_expert,
883	                       int cached_num_recv_tokens,
884	                       int cached_num_rdma_recv_tokens,
885	                       const std::optional<torch::Tensor>& cached_rdma_channel_prefix_matrix,
886	                       const std::optional<torch::Tensor>& cached_recv_rdma_rank_prefix_sum,
887	                       const std::optional<torch::Tensor>& cached_gbl_channel_prefix_matrix,
888	                       const std::optional<torch::Tensor>& cached_recv_gbl_rank_prefix_sum,
889	                       int expert_alignment,
890	                       int num_worst_tokens,
891	                       const Config& config,
892	                       std::optional<EventHandle>& previous_event,
893	                       bool async,
894	                       bool allocate_on_comm_stream) {
895	        // In dispatch, CPU will busy-wait until GPU receive tensor size metadata from other ranks, which can be quite long.
896	        // If users of DeepEP need to execute other Python code on other threads, such as KV transfer, their code will get stuck due to GIL
897	        // unless we release GIL here.
898	        pybind11::gil_scoped_release release;
899	
900	        const int num_channels = config.num_sms / 2;
901	        EP_HOST_ASSERT(config.num_sms % 2 == 0);
902	        EP_HOST_ASSERT(0 < get_num_rdma_ranks() and get_num_rdma_ranks() <= LEGACY_NUM_MAX_RDMA_PEERS);
903	
904	        bool cached_mode = cached_rdma_channel_prefix_matrix.has_value();
905	        if (cached_mode) {
906	            EP_HOST_ASSERT(cached_rdma_channel_prefix_matrix.has_value());
907	            EP_HOST_ASSERT(cached_recv_rdma_rank_prefix_sum.has_value());
908	            EP_HOST_ASSERT(cached_gbl_channel_prefix_matrix.has_value());
