1311	        int num_topk = 0;
1312	        auto combined_topk_weights = std::optional<torch::Tensor>();
1313	        float* topk_weights_ptr = nullptr;
1314	        float* combined_topk_weights_ptr = nullptr;
1315	        if (topk_weights.has_value()) {
1316	            EP_HOST_ASSERT(topk_weights->dim() == 2 and topk_weights->is_contiguous());
1317	            EP_HOST_ASSERT(topk_weights->size(0) == num_tokens);
1318	            EP_HOST_ASSERT(topk_weights->scalar_type() == torch::kFloat32);
1319	            num_topk = static_cast<int>(topk_weights->size(1));
1320	            topk_weights_ptr = topk_weights->data_ptr<float>();
1321	            combined_topk_weights = torch::empty({num_combined_tokens, num_topk}, topk_weights->options());
1322	            combined_topk_weights_ptr = combined_topk_weights->data_ptr<float>();
1323	        }
1324	
1325	        // Extra check for avoid-dead-lock design
1326	        EP_HOST_ASSERT(config.num_max_nvl_chunked_recv_tokens % num_rdma_ranks == 0);
1327	        EP_HOST_ASSERT(config.num_max_nvl_chunked_send_tokens <= config.num_max_nvl_chunked_recv_tokens / num_rdma_ranks);
1328	
1329	        // Launch barrier and reset queue head and tail
1330	        internode::cached_notify(hidden_int4,
1331	                                 0,
1332	                                 0,
1333	                                 num_topk,
1334	                                 num_ranks,
1335	                                 num_channels,
1336	                                 num_combined_tokens,
1337	                                 combined_rdma_head.data_ptr<int>(),
1338	                                 rdma_channel_prefix_matrix.data_ptr<int>(),
1339	                                 rdma_rank_prefix_sum.data_ptr<int>(),
1340	                                 combined_nvl_head.data_ptr<int>(),
1341	                                 rdma_buffer_ptr,
1342	                                 config.num_max_rdma_chunked_recv_tokens,
1343	                                 buffer_ptrs_gpu,
1344	                                 config.num_max_nvl_chunked_recv_tokens,
1345	                                 barrier_signal_ptrs_gpu,
1346	                                 rank,
1347	                                 comm_stream,
1348	                                 config.get_rdma_buffer_size_hint(hidden_int4 * sizeof(int4), num_ranks),
1349	                                 num_nvl_bytes,
1350	                                 false,
1351	                                 low_latency_mode);
1352	
1353	        // Assign bias pointers
1354	        auto bias_opts = std::vector<std::optional<torch::Tensor>>({bias_0, bias_1});
1355	        void* bias_ptrs[2] = {nullptr, nullptr};
1356	        for (int i = 0; i < 2; ++i)
1357	            if (bias_opts[i].has_value()) {
1358	                auto bias = bias_opts[i].value();
1359	                EP_HOST_ASSERT(bias.dim() == 2 and bias.is_contiguous());
1360	                EP_HOST_ASSERT(bias.scalar_type() == x.scalar_type());
1361	                EP_HOST_ASSERT(bias.size(0) == num_combined_tokens and bias.size(1) == hidden);
1362	                bias_ptrs[i] = bias.data_ptr();
1363	            }
1364	
1365	        // Launch data combine
1366	        auto combined_x = torch::empty({num_combined_tokens, hidden}, x.options());
1367	        internode::combine(at::cuda::ScalarTypeToCudaDataType(x.scalar_type()),
1368	                           combined_x.data_ptr(),
1369	                           combined_topk_weights_ptr,
1370	                           is_combined_token_in_rank.data_ptr<bool>(),
1371	                           x.data_ptr(),
1372	                           topk_weights_ptr,
1373	                           bias_ptrs[0],
1374	                           bias_ptrs[1],
1375	                           combined_rdma_head.data_ptr<int>(),
1376	                           combined_nvl_head.data_ptr<int>(),
1377	                           src_meta.data_ptr(),
1378	                           rdma_channel_prefix_matrix.data_ptr<int>(),
1379	                           rdma_rank_prefix_sum.data_ptr<int>(),
1380	                           gbl_channel_prefix_matrix.data_ptr<int>(),
1381	                           num_tokens,
1382	                           num_combined_tokens,
1383	                           hidden,
1384	                           num_topk,
1385	                           rdma_buffer_ptr,
1386	                           config.num_max_rdma_chunked_send_tokens,
1387	                           config.num_max_rdma_chunked_recv_tokens,
1388	                           buffer_ptrs_gpu,
1389	                           config.num_max_nvl_chunked_send_tokens,
1390	                           config.num_max_nvl_chunked_recv_tokens,
1391	                           rank,
1392	                           num_ranks,
1393	                           comm_stream,
1394	                           num_channels,
1395	                           low_latency_mode);
1396	
1397	        // Wait streams
1398	        std::optional<EventHandle> event;
1399	        if (async) {
1400	            event = EventHandle(comm_stream);
1401	            for (auto& t : {x,
1402	                            src_meta,
1403	                            is_combined_token_in_rank,
1404	                            rdma_channel_prefix_matrix,
1405	                            rdma_rank_prefix_sum,
1406	                            gbl_channel_prefix_matrix,
1407	                            combined_x,
1408	                            combined_rdma_head,
1409	                            combined_nvl_head}) {
1410	                t.record_stream(comm_stream);
1411	                if (allocate_on_comm_stream)
1412	                    t.record_stream(compute_stream);
1413	            }
1414	            for (auto& to : {topk_weights, combined_topk_weights, bias_0, bias_1}) {
1415	                to.has_value() ? to->record_stream(comm_stream) : void();
1416	                if (allocate_on_comm_stream)
1417	                    to.has_value() ? to->record_stream(compute_stream) : void();
1418	            }
1419	        } else {
1420	            stream_wait(compute_stream, comm_stream);
1421	        }
1422	
1423	        // Switch back compute stream
1424	        if (allocate_on_comm_stream)
1425	            at::cuda::setCurrentCUDAStream(compute_stream);
1426	
1427	        // Return values
1428	        return {combined_x, combined_topk_weights, event};
1429	    }
