1431	    void clean_low_latency_buffer(int num_max_dispatch_tokens_per_rank, int hidden, int num_experts) {
1432	        EP_HOST_ASSERT(low_latency_mode);
1433	
1434	        auto layout = LowLatencyLayout(rdma_buffer_ptr, num_max_dispatch_tokens_per_rank, hidden, num_ranks, num_experts);
1435	        auto clean_meta_0 = layout.buffers[0].clean_meta();
1436	        auto clean_meta_1 = layout.buffers[1].clean_meta();
1437	
1438	        auto check_boundary = [=, this](void* ptr, size_t num_bytes) {
1439	            auto offset = reinterpret_cast<int64_t>(ptr) - reinterpret_cast<int64_t>(rdma_buffer_ptr);
1440	            EP_HOST_ASSERT(0 <= offset and offset + num_bytes <= num_rdma_bytes);
1441	        };
1442	        check_boundary(clean_meta_0.first, clean_meta_0.second * sizeof(int));
1443	        check_boundary(clean_meta_1.first, clean_meta_1.second * sizeof(int));
1444	
1445	        internode_ll::clean_low_latency_buffer(clean_meta_0.first,
1446	                                               clean_meta_0.second,
1447	                                               clean_meta_1.first,
1448	                                               clean_meta_1.second,
1449	                                               rank,
1450	                                               num_ranks,
1451	                                               mask_buffer_ptr,
1452	                                               sync_buffer_ptr,
1453	                                               at::cuda::getCurrentCUDAStream());
1454	    }
