1456	    std::tuple<torch::Tensor,
1457	               std::optional<torch::Tensor>,
1458	               torch::Tensor,
1459	               torch::Tensor,
1460	               torch::Tensor,
1461	               std::optional<EventHandle>,
1462	               std::optional<std::function<void()>>>
1463	    low_latency_dispatch(const torch::Tensor& x,
1464	                         const torch::Tensor& topk_idx,
1465	                         const std::optional<torch::Tensor>& cumulative_local_expert_recv_stats,
1466	                         const std::optional<torch::Tensor>& dispatch_wait_recv_cost_stats,
1467	                         int num_max_dispatch_tokens_per_rank,
1468	                         int num_experts,
1469	                         bool use_fp8,
1470	                         bool round_scale,
1471	                         bool use_ue8m0,
1472	                         bool async,
1473	                         bool return_recv_hook) {
1474	        EP_HOST_ASSERT(low_latency_mode);
1475	
1476	        // Tensor checks
1477	        // By default using `ptp128c` FP8 cast
1478	        EP_HOST_ASSERT(x.dim() == 2 and x.is_contiguous() and x.scalar_type() == torch::kBFloat16);
1479	        EP_HOST_ASSERT(x.size(1) % sizeof(int4) == 0 and x.size(1) % 128 == 0);
1480	        EP_HOST_ASSERT(topk_idx.dim() == 2 and topk_idx.is_contiguous());
1481	        EP_HOST_ASSERT(x.size(0) == topk_idx.size(0) and x.size(0) <= num_max_dispatch_tokens_per_rank);
1482	        EP_HOST_ASSERT(topk_idx.scalar_type() == c10::CppTypeToScalarType<topk_idx_t>::value);
1483	        EP_HOST_ASSERT(num_experts % num_ranks == 0);
1484	
1485	        // Diagnosis tensors
1486	        if (cumulative_local_expert_recv_stats.has_value()) {
1487	            EP_HOST_ASSERT(cumulative_local_expert_recv_stats->scalar_type() == torch::kInt);
1488	            EP_HOST_ASSERT(cumulative_local_expert_recv_stats->dim() == 1 and cumulative_local_expert_recv_stats->is_contiguous());
1489	            EP_HOST_ASSERT(cumulative_local_expert_recv_stats->size(0) == num_experts / num_ranks);
1490	        }
1491	        if (dispatch_wait_recv_cost_stats.has_value()) {
1492	            EP_HOST_ASSERT(dispatch_wait_recv_cost_stats->scalar_type() == torch::kInt64);
1493	            EP_HOST_ASSERT(dispatch_wait_recv_cost_stats->dim() == 1 and dispatch_wait_recv_cost_stats->is_contiguous());
1494	            EP_HOST_ASSERT(dispatch_wait_recv_cost_stats->size(0) == num_ranks);
1495	        }
1496	
1497	        auto num_tokens = static_cast<int>(x.size(0)), hidden = static_cast<int>(x.size(1));
1498	        auto num_topk = static_cast<int>(topk_idx.size(1));
1499	        auto num_local_experts = num_experts / num_ranks;
1500	
1501	        // Buffer control
1502	        LowLatencyLayout layout(rdma_buffer_ptr, num_max_dispatch_tokens_per_rank, hidden, num_ranks, num_experts);
1503	        EP_HOST_ASSERT(layout.total_bytes <= num_rdma_bytes);
1504	        auto buffer = layout.buffers[low_latency_buffer_idx];
1505	        auto next_buffer = layout.buffers[low_latency_buffer_idx ^= 1];
1506	
1507	        // Wait previous tasks to be finished
1508	        // NOTES: the hook mode will always use the default stream
1509	        auto compute_stream = at::cuda::getCurrentCUDAStream();
1510	        auto launch_stream = return_recv_hook ? compute_stream : comm_stream;
1511	        EP_HOST_ASSERT(not(async and return_recv_hook));
1512	        if (not return_recv_hook)
1513	            stream_wait(launch_stream, compute_stream);
1514	
1515	        // Allocate packed tensors
1516	        auto packed_recv_x = torch::empty({num_local_experts, num_ranks * num_max_dispatch_tokens_per_rank, hidden},
1517	                                          x.options().dtype(use_fp8 ? torch::kFloat8_e4m3fn : torch::kBFloat16));
1518	        auto packed_recv_src_info =
1519	            torch::empty({num_local_experts, num_ranks * num_max_dispatch_tokens_per_rank}, torch::dtype(torch::kInt32).device(torch::kCUDA));
1520	        auto packed_recv_layout_range = torch::empty({num_local_experts, num_ranks}, torch::dtype(torch::kInt64).device(torch::kCUDA));
1521	        auto packed_recv_count = torch::empty({num_local_experts}, torch::dtype(torch::kInt32).device(torch::kCUDA));
1522	
1523	        // Allocate column-majored scales
1524	        auto packed_recv_x_scales = std::optional<torch::Tensor>();
1525	        void* packed_recv_x_scales_ptr = nullptr;
1526	        EP_HOST_ASSERT((num_ranks * num_max_dispatch_tokens_per_rank) % 4 == 0 and "TMA requires the number of tokens to be multiple of 4");
1527	
1528	        if (use_fp8) {
1529	            // TODO: support unaligned cases
1530	            EP_HOST_ASSERT(hidden % 512 == 0);
1531	            if (not use_ue8m0) {
1532	                packed_recv_x_scales = torch::empty({num_local_experts, hidden / 128, num_ranks * num_max_dispatch_tokens_per_rank},
1533	                                                    torch::dtype(torch::kFloat32).device(torch::kCUDA));
1534	            } else {
1535	                EP_HOST_ASSERT(round_scale);
1536	                packed_recv_x_scales = torch::empty({num_local_experts, hidden / 512, num_ranks * num_max_dispatch_tokens_per_rank},
1537	                                                    torch::dtype(torch::kInt).device(torch::kCUDA));
1538	            }
1539	            packed_recv_x_scales = torch::transpose(packed_recv_x_scales.value(), 1, 2);
1540	            packed_recv_x_scales_ptr = packed_recv_x_scales->data_ptr();
1541	        }
1542	
1543	        // Kernel launch
1544	        auto next_clean_meta = next_buffer.clean_meta();
1545	        auto launcher = [=, this](int phases) {
1546	            internode_ll::dispatch(
1547	                packed_recv_x.data_ptr(),
1548	                packed_recv_x_scales_ptr,
1549	                packed_recv_src_info.data_ptr<int>(),
1550	                packed_recv_layout_range.data_ptr<int64_t>(),
1551	                packed_recv_count.data_ptr<int>(),
1552	                mask_buffer_ptr,
1553	                cumulative_local_expert_recv_stats.has_value() ? cumulative_local_expert_recv_stats->data_ptr<int>() : nullptr,
1554	                dispatch_wait_recv_cost_stats.has_value() ? dispatch_wait_recv_cost_stats->data_ptr<int64_t>() : nullptr,
1555	                buffer.dispatch_rdma_recv_data_buffer,
1556	                buffer.dispatch_rdma_recv_count_buffer,
1557	                buffer.dispatch_rdma_send_buffer,
1558	                x.data_ptr(),
1559	                topk_idx.data_ptr<topk_idx_t>(),
1560	                next_clean_meta.first,
1561	                next_clean_meta.second,
1562	                num_tokens,
1563	                hidden,
1564	                num_max_dispatch_tokens_per_rank,
1565	                num_topk,
1566	                num_experts,
1567	                rank,
1568	                num_ranks,
1569	                use_fp8,
1570	                round_scale,
1571	                use_ue8m0,
1572	                workspace,
1573	                num_device_sms,
1574	                launch_stream,
1575	                phases);
1576	        };
1577	        launcher(return_recv_hook ? LEGACY_LOW_LATENCY_SEND_PHASE : (LEGACY_LOW_LATENCY_SEND_PHASE | LEGACY_LOW_LATENCY_RECV_PHASE));
1578	
1579	        // Wait streams
1580	        std::optional<EventHandle> event;
1581	        if (async) {
1582	            // NOTES: we must ensure the all tensors will not be deallocated before the stream-wait happens,
1583	            // so in Python API, we must wrap all tensors into the event handle.
1584	            event = EventHandle(launch_stream);
1585	        } else if (not return_recv_hook) {
1586	            stream_wait(compute_stream, launch_stream);
1587	        }
1588	
1589	        // Receiver callback
1590	        std::optional<std::function<void()>> recv_hook = std::nullopt;
1591	        if (return_recv_hook)
1592	            recv_hook = [=]() { launcher(LEGACY_LOW_LATENCY_RECV_PHASE); };
1593	
1594	        // Return values
1595	        return {packed_recv_x, packed_recv_x_scales, packed_recv_count, packed_recv_src_info, packed_recv_layout_range, event, recv_hook};
1596	    }
