1598	    std::tuple<torch::Tensor, std::optional<EventHandle>, std::optional<std::function<void()>>> low_latency_combine(
1599	        const torch::Tensor& x,
1600	        const torch::Tensor& topk_idx,
1601	        const torch::Tensor& topk_weights,
1602	        const torch::Tensor& src_info,
1603	        const torch::Tensor& layout_range,
1604	        const std::optional<torch::Tensor>& combine_wait_recv_cost_stats,
1605	        int num_max_dispatch_tokens_per_rank,
1606	        int num_experts,
1607	        bool use_logfmt,
1608	        bool zero_copy,
1609	        bool async,
1610	        bool return_recv_hook,
1611	        const std::optional<torch::Tensor>& out = std::nullopt) {
1612	        EP_HOST_ASSERT(low_latency_mode);
1613	
1614	        // Tensor checks
1615	        EP_HOST_ASSERT(x.dim() == 3 and x.is_contiguous() and x.scalar_type() == torch::kBFloat16);
1616	        EP_HOST_ASSERT(x.size(0) == num_experts / num_ranks);
1617	        EP_HOST_ASSERT(x.size(1) == num_ranks * num_max_dispatch_tokens_per_rank);
1618	        EP_HOST_ASSERT(x.size(2) % sizeof(int4) == 0 and x.size(2) % 128 == 0);
1619	        EP_HOST_ASSERT(topk_idx.dim() == 2 and topk_idx.is_contiguous());
1620	        EP_HOST_ASSERT(topk_idx.size(0) == topk_weights.size(0) and topk_idx.size(1) == topk_weights.size(1));
1621	        EP_HOST_ASSERT(topk_idx.scalar_type() == c10::CppTypeToScalarType<topk_idx_t>::value);
1622	        EP_HOST_ASSERT(topk_weights.dim() == 2 and topk_weights.is_contiguous());
1623	        EP_HOST_ASSERT(topk_weights.size(0) <= num_max_dispatch_tokens_per_rank);
1624	        EP_HOST_ASSERT(topk_weights.scalar_type() == torch::kFloat32);
1625	        EP_HOST_ASSERT(src_info.dim() == 2 and src_info.is_contiguous());
1626	        EP_HOST_ASSERT(src_info.scalar_type() == torch::kInt32 and x.size(0) == src_info.size(0));
1627	        EP_HOST_ASSERT(layout_range.dim() == 2 and layout_range.is_contiguous());
1628	        EP_HOST_ASSERT(layout_range.scalar_type() == torch::kInt64);
1629	        EP_HOST_ASSERT(layout_range.size(0) == num_experts / num_ranks and layout_range.size(1) == num_ranks);
1630	
1631	        if (combine_wait_recv_cost_stats.has_value()) {
1632	            EP_HOST_ASSERT(combine_wait_recv_cost_stats->scalar_type() == torch::kInt64);
1633	            EP_HOST_ASSERT(combine_wait_recv_cost_stats->dim() == 1 and combine_wait_recv_cost_stats->is_contiguous());
1634	            EP_HOST_ASSERT(combine_wait_recv_cost_stats->size(0) == num_ranks);
1635	        }
1636	
1637	        auto hidden = static_cast<int>(x.size(2));
1638	        auto num_topk = static_cast<int>(topk_weights.size(1));
1639	        auto num_combined_tokens = static_cast<int>(topk_weights.size(0));
1640	
1641	        // Buffer control
1642	        LowLatencyLayout layout(rdma_buffer_ptr, num_max_dispatch_tokens_per_rank, hidden, num_ranks, num_experts);
1643	        EP_HOST_ASSERT(layout.total_bytes <= num_rdma_bytes);
1644	        auto buffer = layout.buffers[low_latency_buffer_idx];
1645	        auto next_buffer = layout.buffers[low_latency_buffer_idx ^= 1];
1646	
1647	        // Wait previous tasks to be finished
1648	        // NOTES: the hook mode will always use the default stream
1649	        auto compute_stream = at::cuda::getCurrentCUDAStream();
1650	        auto launch_stream = return_recv_hook ? compute_stream : comm_stream;
1651	        EP_HOST_ASSERT(not(async and return_recv_hook));
1652	        if (not return_recv_hook)
1653	            stream_wait(launch_stream, compute_stream);
1654	
1655	        // Allocate output tensor
1656	        torch::Tensor combined_x;
1657	        if (out.has_value()) {
1658	            EP_HOST_ASSERT(out->dim() == 2 and out->is_contiguous());
1659	            EP_HOST_ASSERT(out->size(0) == num_combined_tokens and out->size(1) == hidden);
1660	            EP_HOST_ASSERT(out->scalar_type() == x.scalar_type());
1661	            combined_x = out.value();
1662	        } else {
1663	            combined_x = torch::empty({num_combined_tokens, hidden}, x.options());
1664	        }
1665	
1666	        // Kernel launch
1667	        auto next_clean_meta = next_buffer.clean_meta();
1668	        auto launcher = [=, this](int phases) {
1669	            internode_ll::combine(combined_x.data_ptr(),
1670	                                  buffer.combine_rdma_recv_data_buffer,
1671	                                  buffer.combine_rdma_recv_flag_buffer,
1672	                                  buffer.combine_rdma_send_buffer,
1673	                                  x.data_ptr(),
1674	                                  topk_idx.data_ptr<topk_idx_t>(),
1675	                                  topk_weights.data_ptr<float>(),
1676	                                  src_info.data_ptr<int>(),
1677	                                  layout_range.data_ptr<int64_t>(),
1678	                                  mask_buffer_ptr,
1679	                                  combine_wait_recv_cost_stats.has_value() ? combine_wait_recv_cost_stats->data_ptr<int64_t>() : nullptr,
1680	                                  next_clean_meta.first,
1681	                                  next_clean_meta.second,
1682	                                  num_combined_tokens,
1683	                                  hidden,
1684	                                  num_max_dispatch_tokens_per_rank,
1685	                                  num_topk,
1686	                                  num_experts,
1687	                                  rank,
1688	                                  num_ranks,
1689	                                  use_logfmt,
1690	                                  workspace,
1691	                                  num_device_sms,
1692	                                  launch_stream,
1693	                                  phases,
1694	                                  zero_copy);
1695	        };
1696	        launcher(return_recv_hook ? LEGACY_LOW_LATENCY_SEND_PHASE : (LEGACY_LOW_LATENCY_SEND_PHASE | LEGACY_LOW_LATENCY_RECV_PHASE));
1697	
1698	        // Wait streams
1699	        std::optional<EventHandle> event;
1700	        if (async) {
1701	            // NOTES: we must ensure the all tensors will not be deallocated before the stream-wait happens,
1702	            // so in Python API, we must wrap all tensors into the event handle.
1703	            event = EventHandle(launch_stream);
1704	        } else if (not return_recv_hook) {
1705	            stream_wait(compute_stream, launch_stream);
1706	        }
1707	
1708	        // Receiver callback
1709	        std::optional<std::function<void()>> recv_hook = std::nullopt;
1710	        if (return_recv_hook)
1711	            recv_hook = [=]() { launcher(LEGACY_LOW_LATENCY_RECV_PHASE); };
1712	
1713	        // Return values
1714	        return {combined_x, event, recv_hook};
1715	    }
