1717	    torch::Tensor get_next_low_latency_combine_buffer(int num_max_dispatch_tokens_per_rank, int hidden, int num_experts) const {
1718	        LowLatencyLayout layout(rdma_buffer_ptr, num_max_dispatch_tokens_per_rank, hidden, num_ranks, num_experts);
1719	
1720	        auto buffer = layout.buffers[low_latency_buffer_idx];
1721	        auto dtype = torch::kBFloat16;
1722	        auto num_msg_elems = static_cast<int>(buffer.num_bytes_per_combine_msg / elementSize(torch::kBFloat16));
1723	
1724	        EP_HOST_ASSERT(buffer.num_bytes_per_combine_msg % elementSize(torch::kBFloat16) == 0);
1725	        return torch::from_blob(buffer.combine_rdma_send_buffer_data_start,
1726	                                {num_experts / num_ranks, num_ranks * num_max_dispatch_tokens_per_rank, hidden},
1727	                                {num_ranks * num_max_dispatch_tokens_per_rank * num_msg_elems, num_msg_elems, 1},
1728	                                torch::TensorOptions().dtype(dtype).device(torch::kCUDA));
1729	    }
