75	    size_t get_rdma_buffer_size_hint(int64_t hidden_bytes, int num_ranks) const {
76	        // Legacy mode
77	        if (num_ranks <= LEGACY_NUM_MAX_NVL_PEERS)
78	            return 0;
79	
80	        // Below are some assumptions
81	        // TODO: add assertions
82	        constexpr int kNumMaxTopK = 128;
83	        constexpr int kNumMaxScales = 128;
84	        EP_HOST_ASSERT(num_ranks % LEGACY_NUM_MAX_NVL_PEERS == 0);
85	        EP_HOST_ASSERT(num_sms % 2 == 0);
86	        const int num_rdma_ranks = num_ranks / LEGACY_NUM_MAX_NVL_PEERS;
87	        const int num_channels = num_sms / 2;
88	
89	        size_t num_bytes = 0;
90	        num_bytes += num_channels * num_rdma_ranks * (LEGACY_NUM_MAX_NVL_PEERS * 2 + 2) * 2 * sizeof(int);
91	        num_bytes += num_channels * num_rdma_ranks * num_max_rdma_chunked_recv_tokens * hidden_bytes * 2;
92	        num_bytes += num_channels * num_rdma_ranks * num_max_rdma_chunked_recv_tokens * internode::get_source_meta_bytes() * 2;
93	        num_bytes += num_channels * num_rdma_ranks * num_max_rdma_chunked_recv_tokens * kNumMaxTopK * sizeof(topk_idx_t) * 2;
94	        num_bytes += num_channels * num_rdma_ranks * num_max_rdma_chunked_recv_tokens * kNumMaxTopK * sizeof(float) * 2;
95	        num_bytes += num_channels * num_rdma_ranks * num_max_rdma_chunked_recv_tokens * kNumMaxScales * sizeof(float) * 2;
96	        num_bytes += num_channels * num_rdma_ranks * num_max_rdma_chunked_recv_tokens * sizeof(int4) * 2;
97	        num_bytes = ((num_bytes + 127) / 128) * 128;
98	        return num_bytes;
99	    }
100	};
101	
102	struct LowLatencyBuffer {
103	    int num_clean_int = 0;
104	
105	    void* dispatch_rdma_send_buffer = nullptr;
106	    void* dispatch_rdma_recv_data_buffer = nullptr;
107	    int* dispatch_rdma_recv_count_buffer = nullptr;
108	
109	    void* combine_rdma_send_buffer = nullptr;
110	    void* combine_rdma_recv_data_buffer = nullptr;
111	    int* combine_rdma_recv_flag_buffer = nullptr;
112	
113	    void* combine_rdma_send_buffer_data_start = nullptr;
114	    size_t num_bytes_per_combine_msg = 0;
115	
116	    std::pair<int*, int> clean_meta() {
117	        EP_HOST_ASSERT(dispatch_rdma_recv_count_buffer == combine_rdma_recv_flag_buffer);
118	        return {dispatch_rdma_recv_count_buffer, num_clean_int};
119	    }
120	};
