122	struct LowLatencyLayout {
123	    size_t total_bytes = 0;
124	    LowLatencyBuffer buffers[2];
125	
126	    template <typename out_ptr_t = void*, typename count_ptr_t = uint8_t*, typename in_ptr_t = void*>
127	    out_ptr_t advance(const in_ptr_t& ptr, size_t count) {
128	        return reinterpret_cast<out_ptr_t>(reinterpret_cast<count_ptr_t>(ptr) + count);
129	    }
130	
131	    LowLatencyLayout(void* rdma_buffer, int num_max_dispatch_tokens_per_rank, int hidden, int num_ranks, int num_experts) {
132	        const int num_scales = hidden / 128;
133	
134	        // Dispatch and combine layout:
135	        //  - 2 symmetric odd/even send buffer
136	        //  - 2 symmetric odd/even receive buffers
137	        //  - 2 symmetric odd/even signaling buffers
138	
139	        // Message sizes
140	        // NOTES: you should add a control `int4` for combine messages if you want to do data transformation
141	        // NOTES: `num_scales * sizeof(nv_bfloat162)` means the per-128-channel min/max
142	        EP_HOST_ASSERT(num_scales * sizeof(float) <= hidden);
143	        size_t num_bytes_per_dispatch_msg = sizeof(int4) + std::max(hidden * sizeof(nv_bfloat16), hidden + num_scales * sizeof(float));
144	        size_t num_bytes_per_combine_msg = num_scales * sizeof(nv_bfloat162) + hidden * sizeof(nv_bfloat16);
145	
146	        // Send buffer
147	        size_t dispatch_send_buffer_bytes = num_max_dispatch_tokens_per_rank * num_bytes_per_dispatch_msg;
148	        size_t combine_send_buffer_bytes = num_experts * num_max_dispatch_tokens_per_rank * num_bytes_per_combine_msg;
149	        size_t send_buffer_bytes = std::max(dispatch_send_buffer_bytes, combine_send_buffer_bytes);
150	        EP_HOST_ASSERT(send_buffer_bytes % sizeof(int4) == 0);
151	        total_bytes += send_buffer_bytes * 2;
152	
153	        // Symmetric receive buffers
154	        // TODO: optimize memory usages
155	        size_t dispatch_recv_data_buffer_bytes = num_experts * num_max_dispatch_tokens_per_rank * num_bytes_per_dispatch_msg;
156	        size_t combine_recv_buffer_bytes = num_experts * num_max_dispatch_tokens_per_rank * num_bytes_per_combine_msg;
157	        size_t recv_buffer_bytes = std::max(dispatch_recv_data_buffer_bytes, combine_recv_buffer_bytes);
158	        EP_HOST_ASSERT(recv_buffer_bytes % sizeof(int4) == 0);
159	        total_bytes += recv_buffer_bytes * 2;
