162	        size_t dispatch_recv_count_buffer_bytes = num_experts * sizeof(int);
163	        size_t combine_recv_flag_buffer_bytes = dispatch_recv_count_buffer_bytes;
164	        size_t signaling_buffer_bytes = std::max(dispatch_recv_count_buffer_bytes, combine_recv_flag_buffer_bytes);
165	        size_t signaling_buffer_bytes_aligned = align_up<size_t>(signaling_buffer_bytes, 128);
166	        total_bytes += signaling_buffer_bytes_aligned * 2;
167	
168	        // Assign pointers
169	        // NOTES: we still leave some space for distinguishing dispatch/combine buffer,
170	        // so you may see some parameters are duplicated
171	        for (int i = 0; i < 2; ++i) {
172	            buffers[i] = {static_cast<int>(signaling_buffer_bytes / sizeof(int)),
173	                          advance(rdma_buffer, signaling_buffer_bytes_aligned * 2 + send_buffer_bytes * i),
174	                          advance(rdma_buffer, signaling_buffer_bytes_aligned * 2 + send_buffer_bytes * 2 + recv_buffer_bytes * i),
175	                          advance<int*>(rdma_buffer, signaling_buffer_bytes_aligned * i),
176	                          advance(rdma_buffer, signaling_buffer_bytes_aligned * 2 + send_buffer_bytes * i),
177	                          advance(rdma_buffer, signaling_buffer_bytes_aligned * 2 + send_buffer_bytes * 2 + recv_buffer_bytes * i),
